  CardModel(id: 'wirtschaftlichkeitKarten-004', question: 'Was ist der Break-Even-Point?', shortAnswer: 'Der Punkt, bei dem Erlöse und Kosten gleich sind – weder Gewinn noch Verlust', longAnswer: 'Formel: Break-Even-Menge = Fixkosten / Deckungsbeitrag pro StückBeispiel: Fixkosten 10.000€, Stückpreis 50€, variable Kosten 30€→ DB = 50 – 30 = 20€→ Break-Even = 10.000 / 20 = 500 StückBedeutung: Ab 500 Stück wird Gewinn erzielt; unter 500 Stück Verlust.Grafisch: Schnittpunkt von Erlös- und Gesamtkostenkurve.', url: '', hashtags: ['#Wirtschaft', '#Kalkulation', '#AP1']),
